/** Icon mapping for tool step types */
const TOOL_ICONS: Record<string, string> = {
  bash: "terminal",
  edit: "pencil",
  read: "doc.text",
  write: "square.and.pencil",
  search: "magnifyingglass",
  think: "brain.head.profile",
  grep: "magnifyingglass",
  glob: "folder",
};

function ThinkingIndicator({
  status,
  toolSteps,
  permissionRequests,
  onApprove,
  onDeny,
  isDark,
}: {
  status: ThreadStatus;
  toolSteps: ToolStep[];
  permissionRequests: PermissionRequest[];
  onApprove: (id: string) => void;
  onDeny: (id: string) => void;
  isDark: boolean;
}) {
  const latestRunning = toolSteps.filter((s) => s.status === "running");
  const recentDone = toolSteps.filter((s) => s.status === "done").slice(-3);

  const statusLabel = status === "waiting" ? "Waiting for approval…" : "Thinking…";
  const statusColor = status === "waiting" ? AC.systemOrange : AC.systemBlue;

  return (
    <View style={{ gap: SPACING.sm, paddingTop: SPACING.xs }}>
      {/* Main status pill */}
      <View
        style={{
          flexDirection: "row",
          alignItems: "center",
          gap: 8,
          paddingHorizontal: SPACING.md,
          paddingVertical: SPACING.xs,
          backgroundColor: isDark
            ? status === "waiting"
              ? "rgba(255,149,0,0.12)"
              : "rgba(10,132,255,0.12)"
            : status === "waiting"
              ? "rgba(255,149,0,0.08)"
              : "rgba(10,132,255,0.08)",
          borderRadius: BORDER_RADIUS.full,
          alignSelf: "flex-start",
        }}
      >
        <ActivityIndicator size="small" color={statusColor} />
        <Text style={{ color: statusColor, fontSize: 12, fontWeight: "500" }}>
          {statusLabel}
        </Text>
      </View>

      {/* Active tool steps */}
      {latestRunning.length > 0 && (
        <View style={{ gap: 4, paddingLeft: SPACING.xs }}>
          {latestRunning.map((step) => (
            <View
              key={step.id}
              style={{ flexDirection: "row", alignItems: "center", gap: 6 }}
            >
              <ActivityIndicator size="small" color={AC.systemBlue} />
              <IconSymbol
                name={TOOL_ICONS[step.tool] ?? "hammer"}
                size={11}
                color={AC.systemGray}
              />
              <Text
                style={{
                  color: AC.systemGray,
                  fontSize: 12,
                  fontFamily: Platform.OS === "ios" ? "Menlo" : "monospace",
                }}
                numberOfLines={1}
              >
                {step.label}
              </Text>
            </View>
          ))}
        </View>
      )}

      {/* Recently completed steps — subtle checkmarks */}
      {recentDone.length > 0 && (
        <View style={{ gap: 2, paddingLeft: SPACING.xs }}>
          {recentDone.map((step) => (
            <View
              key={step.id}
              style={{ flexDirection: "row", alignItems: "center", gap: 6 }}
            >
              <IconSymbol name="checkmark" size={10} color={AC.systemGreen} />
              <Text
                style={{
                  color: AC.systemGray3,
                  fontSize: 11,
                }}
                numberOfLines={1}
              >
                {step.label}
              </Text>
            </View>
          ))}
        </View>
      )}

      {/* Permission prompts — inline approval cards */}
      {permissionRequests.length > 0 && (
        <View style={{ gap: SPACING.sm }}>
          {permissionRequests.map((req) => (
            <View
              key={req.id}
              style={{
                backgroundColor: isDark ? "#1c1c1e" : "#fff",
                borderRadius: BORDER_RADIUS.lg,
                borderWidth: 1,
                borderColor: status === "waiting"
                  ? AC.systemOrange
                  : isDark
                    ? "rgba(255,255,255,0.08)"
                    : AC.separator,
                padding: SPACING.md,
                gap: SPACING.sm,
              }}
            >
              <View style={{ flexDirection: "row", alignItems: "center", gap: 6 }}>
                <IconSymbol
                  name={TOOL_ICONS[req.tool] ?? "exclamationmark.shield"}
                  size={14}
                  color={AC.systemOrange}
                />
                <Text style={{ color: AC.label, fontSize: 13, fontWeight: "600" }}>
                  Permission Required
                </Text>
              </View>
              <Text
                style={{
                  color: AC.secondaryLabel,
                  fontSize: 13,
                  lineHeight: 18,
                }}
              >
                {req.description}
              </Text>
              <View style={{ flexDirection: "row", gap: SPACING.sm }}>
                <TouchableBounce
                  sensory
                  onPress={() => onApprove(req.id)}
                >
                  <View
                    style={{
                      backgroundColor: AC.systemBlue,
                      borderRadius: BORDER_RADIUS.md,
                      paddingHorizontal: SPACING.lg,
                      paddingVertical: SPACING.sm,
                    }}
                  >
                    <Text style={{ color: "#fff", fontSize: 13, fontWeight: "600" }}>
                      Allow
                    </Text>
                  </View>
                </TouchableBounce>
                <TouchableBounce
                  sensory
                  onPress={() => onDeny(req.id)}
                >
                  <View
                    style={{
                      backgroundColor: isDark ? "rgba(255,255,255,0.08)" : "rgba(0,0,0,0.05)",
                      borderRadius: BORDER_RADIUS.md,
                      paddingHorizontal: SPACING.lg,
                      paddingVertical: SPACING.sm,
                    }}
                  >
                    <Text style={{ color: AC.label, fontSize: 13, fontWeight: "600" }}>
                      Deny
                    </Text>
                  </View>
                </TouchableBounce>
              </View>
            </View>
          ))}
        </View>
      )}
    </View>
  );
