    "content": "import React, { useCallback, useEffect, useRef, useState } from "react";
import {
  ActivityIndicator,
  Animated,
  FlatList,
  Modal,
  Platform,
  Pressable,
  ScrollView,
  StyleSheet,
  Text,
  TouchableOpacity,
  View,
} from "react-native";
import { useGatewayStore, type FsEntry, type FsListing } from "../store/gatewayStore";

type Props = {
  visible: boolean;
  onSelect: (path: string) => void;
  onCancel: () => void;
};

export default function DirectoryBrowser({ visible, onSelect, onCancel }: Props) {
  const browseFsDirectory = useGatewayStore((s) => s.actions.browseFsDirectory);
  const [listing, setListing] = useState<FsListing | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const slideAnim = useRef(new Animated.Value(700)).current;

  const navigate = useCallback(
    async (path?: string) => {
      setLoading(true);
      setError(null);
      try {
        const result = await browseFsDirectory(path);
        setListing(result);
      } catch (e: any) {
        setError(e.message ?? "Cannot open directory");
      } finally {
        setLoading(false);
      }
    },
    [browseFsDirectory]
  );

  useEffect(() => {
    if (visible) {
      navigate(undefined);
      Animated.spring(slideAnim, {
        toValue: 0,
        useNativeDriver: true,
        tension: 60,
        friction: 12,
      }).start();
    } else {
      slideAnim.setValue(700);
      setListing(null);
      setError(null);
    }
  }, [visible]);

  const breadcrumbs = listing
    ? listing.path
        .split("/")
        .filter(Boolean)
        .map((seg, i, arr) => ({
          label: seg,
          path: "/" + arr.slice(0, i + 1).join("/"),
        }))
    : [];

  const dirs = listing?.entries.filter((e) => e.isDir) ?? [];

  return (
    <Modal
      transparent
      animationType="none"
      visible={visible}
      onRequestClose={onCancel}
    >
      <View style={styles.backdrop}>
        <Pressable style={StyleSheet.absoluteFill} onPress={onCancel} />
        <Animated.View
          style={[styles.sheet, { transform: [{ translateY: slideAnim }] }]}
        >
          {/* Header */}
          <View style={styles.header}>
            <Text style={styles.headerTitle}>Choose Working Directory</Text>
            <TouchableOpacity onPress={onCancel} hitSlop={12}>
              <Text style={styles.headerCancel}>Cancel</Text>
            </TouchableOpacity>
          </View>

          {/* Breadcrumb row */}
          <View style={styles.breadcrumbContainer}>
            <ScrollView
              horizontal
              showsHorizontalScrollIndicator={false}
              contentContainerStyle={styles.breadcrumbScroll}
            >
              {/* Root "/" chip */}
              <TouchableOpacity
                onPress={() => navigate("/")}
                style={styles.breadcrumbChip}
              >
                <Text style={styles.breadcrumbText}>/</Text>
              </TouchableOpacity>
              {breadcrumbs.map((crumb, i) => (
                <React.Fragment key={crumb.path}>
                  <Text style={styles.breadcrumbSep}>›</Text>
                  <TouchableOpacity
                    onPress={() => navigate(crumb.path)}
                    style={[
                      styles.breadcrumbChip,
                      i === breadcrumbs.length - 1 && styles.breadcrumbActive,
                    ]}
                  >
                    <Text
                      style={[
                        styles.breadcrumbText,
                        i === breadcrumbs.length - 1 &&
                          styles.breadcrumbActiveText,
                      ]}
                    >
                      {crumb.label}
                    </Text>
                  </TouchableOpacity>
                </React.Fragment>
              ))}
            </ScrollView>
          </View>

          {/* Body */}
          {loading ? (
            <View style={styles.center}>
              <ActivityIndicator size="large" color="#4ade80" />
            </View>
          ) : error ? (
            <View style={styles.center}>
              <Text style={styles.errorText}>{error}</Text>
              <TouchableOpacity
                style={styles.retryBtn}
                onPress={() => navigate(listing?.path)}
              >
                <Text style={styles.retryText}>Retry</Text>
              </TouchableOpacity>
            </View>
          ) : (
            <FlatList
              data={dirs}
              keyExtractor={(item) => item.path}
              renderItem={({ item }) => (
                <DirectoryRow
                  item={item}
                  onNavigate={() => navigate(item.path)}
                />
              )}
              ListEmptyComponent={
                <View style={styles.center}>
                  <Text style={styles.emptyText}>No sub-directories</Text>
                </View>
              }
              style={styles.list}
            />
          )}

          {/* Footer */}
          <View style={styles.footer}>
            {listing?.parent != null && (
              <TouchableOpacity
                style={styles.upBtn}
                onPress={() => navigate(listing.parent!)}
              >
                <Text style={styles.upText}>↑ Up</Text>
              </TouchableOpacity>
            )}
            <TouchableOpacity
              style={styles.selectBtn}
              onPress={() => listing && onSelect(listing.path)}
              disabled={!listing}
            >
              <Text style={styles.selectText}>
                Open Here
              </Text>
            </TouchableOpacity>
          </View>
        </Animated.View>
      </View>
    </Modal>
  );
}

function DirectoryRow({
  item,
  onNavigate,
}: {
  item: FsEntry;
  onNavigate: () => void;
}) {
  return (
    <TouchableOpacity style={styles.row} onPress={onNavigate}>
      <Text style={styles.rowIcon}>📁</Text>
      <Text style={styles.rowName} numberOfLines={1}>
        {item.name}
      </Text>
      <Text style={styles.rowChevron}>›</Text>
    </TouchableOpacity>
  );
}

const styles = StyleSheet.create({
  backdrop: {
    flex: 1,
